var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"거기까지다, 멈춰.","JPN":"そこまでだ、止まれ。","ENG":"That's as far as you'll go. Enough.","TWN":"住手，到此為止。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"소대장! 어떻게 여기에?","JPN":"小隊長！　なんでここに？","ENG":"Commander! How did you get here?","TWN":"小隊長？你怎麼會在這裡？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님만이 아니군요. 당신은……","JPN":"師匠だけではありませんね、あなたは……","ENG":"It's not just you, Master. But you…","TWN":"師父不是自己一個喔？還有你……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 저희가 아주 늦지는 않은 모양이네요.","JPN":"ハハ、僕たちギリギリ間に合ったようですね。","ENG":"Haha, looks like we haven't missed the entire show.","TWN":"哈哈～看起來我們還不算太晚啦。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"주시윤, 다친 곳은 없나?","JPN":"アキヤマ、ケガはないか？","ENG":"Are you unhurt, Joo Shiyoon?","TWN":"周時雲，你有受傷嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"아니, 잠깐…… 그 칼집은 어디선 난 거지?","JPN":"いや待て……その鞘はどこで手に入れた？","ENG":"Hang on… Where did you get that scabbard?","TWN":"等等……那個劍鞘是哪來的？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너 대체 여기서 무슨 일이 있었던 거냐?","JPN":"ここでいったい何があったんだ？","ENG":"What happened to you here?","TWN":"你在這裡到底發生了什麼事？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"나중에 말씀드릴게요. 여기서 얘기하기엔 좀 길어져서요.","JPN":"それは後にしましょう。ここで話すにはちょっと長くなりそうですので。","ENG":"I'll tell you all about it later. It's a long story.","TWN":"說來話長，之後再跟師父報告。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금은 저 황태자라는 분과의 문제부터 해결하는 게 어떨까요?","JPN":"今はあの皇太子という方との問題から解決したほうがよさそうです。","ENG":"For now, why don't we sort out this issue with that Crown Prince gentleman?","TWN":"現在先解決我跟那個叫皇太子的之間的問題好嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……좋다.","JPN":"……いいだろう。","ENG":"...Very well.","TWN":"……好。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"자세한 보고는 회사로 복귀한 후에 듣도록 하지.","JPN":"詳しい報告は会社に戻った後に聞こう。","ENG":"You can debrief me in detail once we get back to the office.","TWN":"等回到公司你再跟我報告清楚。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네 말대로 지금은 저 녀석부터 처리해야 할 것 같으니까.","JPN":"今はお前の言うとおり、あいつを対処したほうがよさそうだ。","ENG":"Like you said, I think we'll have to deal with this guy first.","TWN":"現在就照你說的先處理那傢伙吧！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이것 참, 오늘은 무대에 난입하는 관객들이 많군.","JPN":"やれやれ、今日は舞台に乱入する観客が多いな。","ENG":"My, my. We have too many hecklers here today.","TWN":"真是的，今天還真多觀眾干擾演出。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이번 세계의 야만인들은 참으로 교양이 부족하단 말이야.","JPN":"この世界の野蛮人たちは実に教養が足りないようだ。","ENG":"These barbarians in this world simply have no class, I tell you.","TWN":"這次的世界好多沒教養的野蠻人。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……쓸데없는 경고겠지만, 일단은 말해 두지.","JPN":"……余計な警告だろうが、一応言っておこう。","ENG":"…I know this will fall on deaf ears, but I'll say it anyway.","TWN":"……雖然你耳朵很硬，但我還是說一下。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"난 내 멍청한 제자 놈을 구하러 온 거다.","JPN":"私はあのマヌケな弟子を助けに来た。","ENG":"I'm just here to rescue my stupid apprentice.","TWN":"我來是要救我的笨徒弟，"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네가 우릴 가로막지 않는다면 굳이 싸우고 싶은 생각은 없어.","JPN":"お前が私たちの邪魔をしないなら、あえて戦うつもりはない。","ENG":"If you won't stand in our way, we don't have to fight.","TWN":"只要你不擋路，我沒有要動手的意思。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……그것 참 그대답지 않은 말이로군, 발키리.","JPN":"……それはまったく貴様らしくない発言だな、ヴァルキリー。","ENG":"…That does not sound like thee at all, Valkyrie.","TWN":"……這真不像你會說的話呢？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};